using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options backed by a source-generated context that only knows about WeatherForecast.
var options = new JsonSerializerOptions
{
    TypeInfoResolver = AppJsonContext.Default,
    WriteIndented    = true
};

// ── 1. Strongly-typed retrieval ──────────────────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<WeatherForecast> meta = options.GetTypeInfo<WeatherForecast>();
Console.WriteLine($"Type      : {meta.Type.Name}");
Console.WriteLine($"Kind      : {meta.Kind}");
Console.WriteLine($"Properties: {meta.Properties.Count}");
Console.WriteLine();

// ── 2. Probe without throwing ────────────────────────────────────────
// TryGetTypeInfo<T>() returns false instead of throwing when the type
// isn't resolvable (here, DateTime is not in our source-gen context).
if (options.TryGetTypeInfo<WeatherForecast>(out JsonTypeInfo<WeatherForecast>? found))
    Console.WriteLine($"WeatherForecast: found  -> {found.Type.Name}");
else
    Console.WriteLine("WeatherForecast: NOT found");

if (options.TryGetTypeInfo<DateTime>(out JsonTypeInfo<DateTime>? _))
    Console.WriteLine("DateTime       : found");
else
    Console.WriteLine("DateTime       : NOT found (no metadata registered)");

// ── types / context ──────────────────────────────────────────────────
public record WeatherForecast(string City, double TempC, DateTime Date);

[JsonSerializable(typeof(WeatherForecast))]
partial class AppJsonContext : JsonSerializerContext;

